var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"어머, 우리 마을을 구해주신 분이군요.","JPN":"まあ、私たちの村を助けてくださった方ですね。","ENG":"Oh my... So you're the one who saved our village.","TWN":"天啊，你們就是拯救我們村子的恩人啊。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"마을을 대표해 감사드려요.","JPN":"村を代表して、お礼を申し上げます。","ENG":"On behalf of everyone here... truly, thank you.","TWN":"我代表村民謝謝你們。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"음?하,하핫이것참쑥쓰럽네나는그냥여기로오라그래서오라그런거니까너무신경쓰지마","JPN":"うん？　は、ははっ、なんだその照れくさいっていうかあたしはただここに行けって言われて来ただけだし気にすんなっていうか","ENG":"Uh? H-haha... that's, uh, really embarrassing, I-I only came because they said to come, so don't... don't mind it too much...","TWN":"欸？哈、哈哈不用放在心上只是叫我來我就來了啦"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네 엄니임다!","JPN":"モネの母ちゃんっす！","ENG":"Mone's mama is here!","TWN":"是莫妮的媽媽！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이, 이렇게 젊어 보이는 사람이 애 엄마라고……?","JPN":"こ、こんなに若く見えるのにこいつの母親だって……？","ENG":"Th-this young-looking lady is a mom...?","TWN":"看、看起來這麼年輕的人是孩子的媽媽……？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"엄니! 마을은 별일 없었슴까?!","JPN":"母ちゃん！　村は大丈夫だったっすか！？","ENG":"Mama! Is the village all right?!","TWN":"媽媽！村子沒事吧？！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그럼! 베로니카 씨와 다른 용병분들이 노력해 주신 덕분이야.","JPN":"もちろんよ！　ベロニカさんと他の傭兵の方々が頑張ってくださったおかげよ。","ENG":"Of course. Veronica and the other mercenaries also helped so much.","TWN":"當然啦！這都要多虧貝洛妮卡小姐和其他傭兵的幫忙。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"예전에는 마을에서 쫓아내겠다고 으르렁거리던 사람들이었는데…….","JPN":"昔は村から追い出すってすごんでいた人たちだったのに……","ENG":"To think those same people once talked about driving us out...","TWN":"是以前那些說要把我們趕出去的人……"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"살다 보니 이런 일도 다 있네.","JPN":"こんなこともあるのね。","ENG":"But I suppose that's life, isn't it?","TWN":"果然活久了什麼事都會發生。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 당시에도 마을 사람들을 쫓아내는 것에 거부감을 느끼던 분들이었습니다.","JPN":"当時も村の人を追い出すことに抵抗感を抱いていたようですよ。","ENG":"Even back then, they were uncomfortable with chasing out villagers.","TWN":"那時候也有不少人反對驅逐村民。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마음의 빚을 갚으러 왔다.</color>라고 했던가요?","JPN":"<color=#ffd34c>心の借りを返すために来た</color>、でしたっけ？","ENG":"I believe they said they'd come to <color=#ffd34c>repay a debt of the heart</color>, wasn't it?","TWN":"說是來<color=#ffd34c>償還心中的債</color>嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"덕분에 마음 놓고 해변으로 나가 침식체를 소탕할 수 있었습니다.","JPN":"おかげで安心して海辺に行き、侵食体を相手することができました。","ENG":"Thanks to them, we were able to head to the beach and clear out the C.O.s without worry.","TWN":"多虧如此，我才能放心到海邊掃蕩侵蝕體。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"물론… 메이드장님이 안 계셨더라면 완전히 안심하지는 못했을 테지만요.","JPN":"もちろん……いざとなればメイド長がいる、という根拠もあったのですが。","ENG":"Though... without the Chief Maid, we wouldn't have felt completely safe.","TWN":"當然……若不是女僕長在，我們可能還是無法安心就是了。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는 뒤에서 지원 사격을 해줬을 뿐이에요. 릴리.","JPN":"私は後ろで支援射撃をしていただけですよ、リリー。","ENG":"I was only providing covering fire from behind, Lily.","TWN":"我只是在後方支援射擊而已，莉莉。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마을을 습격하는 침식체를 소탕한 건 전적으로 용병분들의 활약 덕입니다.","JPN":"村を襲撃する侵食体を掃討したのは、全面的に傭兵の皆さんが活躍してくださったおかげです。","ENG":"Clearing out the C.O.s attacking the village was entirely the mercenaries' achievement.","TWN":"真正掃蕩侵蝕體的是傭兵們的功勞。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"총알 한 발로 침식체 코어를 꿰뚫어 버리는 사람이 할 말은 아닌 것 같은데.","JPN":"銃弾一発で侵食体のコアを貫く人が言うことじゃないと思うけど。","ENG":"Says the woman who pierced a C.O.'s core with one bullet...","TWN":"這好像不是能一發穿透侵蝕體核心的人該說的話。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 깡통. 저 녀석들… 안전한 거 맞아?","JPN":"おい、ポンコツ。あいつら……本当に安全なのか？","ENG":"Hey, tin can. Are those people... actually safe?","TWN":"喂，鐵桶。這些傢伙……真的安全嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그걸 저한테 물어보셔도…….","JPN":"私に聞かれましても……","ENG":"Asking me won't–","TWN":"你問我也……"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"안심하세요, 키이라님.","JPN":"ご安心ください、キーラ様。","ENG":"Rest assured, Miss Kiera.","TWN":"別擔心，琪伊拉。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저희 플로라 메이드가 모시는 주인님은 여러분이 최고 관리자라 부르는 분.","JPN":"私たちフローラメイドが仕えるご主人様は、皆さんが最高管理者とお呼びしているお方。","ENG":"The Master we Flora Maids serve is the one you call the Supreme Administrator.","TWN":"我們芙蘿拉女僕侍奉的主人，就是你們稱為最高管理者的那一位。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님의 뜻은 곧 저희의 뜻이기에, 의심은 거두셔도 됩니다.","JPN":"ご主人様の意志は私たちの意志ですので、疑う必要などありません。","ENG":"His will is our will. You may trust us.","TWN":"主人的意志就是我們的意志，這點無需懷疑。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"사람들을 구해줬다니까, 일단 적이 아니라는 건 믿겠어.","JPN":"住民を助けたらしいから、とりあえず敵じゃないってことは信じるよ。","ENG":"All right... you saved people, so I'll believe you're not the enemy.","TWN":"既然你們救了人，我暫時相信你們不是敵人。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 왜 섬을 떠나지 않는 거야?","JPN":"でも、なんで島から出ないんだ？","ENG":"But why aren't you leaving the island?","TWN":"但你們為什麼不離開這座島？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"지금 바다는 아비규환이라고.","JPN":"今、海はまさに阿鼻叫喚の状態なんだ。","ENG":"The sea is chaos right now.","TWN":"現在海上亂成一團耶。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"직할 도시는 파도처럼 밀려 들어오는 침식체를 처리하느라 애를 먹고 있어.","JPN":"直轄都市は波のように押し寄せてくる侵食体を処理するだけでも手一杯。","ENG":"Front Bay's choking under waves of C.O.s.","TWN":"直轄城市正為湧入的侵蝕體頭痛不已。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나 같은 고위험 범죄자를 사법 거래로 풀어줄 정도로 말이야.","JPN":"あたしみたいな高危険度の犯罪者を司法取引で解放してくれるほどにな。","ENG":"To the point they let a high-risk criminal like me walk out on a judicial deal.","TWN":"甚至都願意透過司法交易讓我這種高危險罪犯出來協助。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그만큼 도시를 지키고 싶은 마음이라는 거겠죠.","JPN":"そうしてでも都市を守りたいということでしょう。","ENG":"If anything, it shows just how much they wanted to protect their home.","TWN":"那大概就是他們想守護城市的心意吧。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"사람의 목숨을, 자신의 자유를 포기하면서까지 지켜야 할 이유가 있는 거야?","JPN":"人の命とか自分の自由を放棄してまで守る理由なんてあるのか？","ENG":"Is there really something worth protecting, even at the cost of people's lives and their freedom?","TWN":"妳有理由犧牲自己的自由，只為了為了保護大家的性命嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"고향은 고향일 뿐이잖아.","JPN":"ただの故郷だろ。","ENG":"A home is just a home.","TWN":"故鄉就是故鄉不是嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};